import{_ as o,o as a,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Enable Google App Campaigns","description":"","frontmatter":{"title":"Enable Google App Campaigns","slug":"enable-google-app-campaigns"},"headers":[],"relativePath":"marketer-hub/enable-google-app-campaigns.md","filePath":"marketer-hub/enable-google-app-campaigns.md"}'),r={name:"marketer-hub/enable-google-app-campaigns.md"};function i(s,e,l,c,p,d){return a(),t("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>By connecting Branch and Google Ads, the following is enabled:</p><ul><li>App conversion data collected by the Branch SDK is sent to Google Ads for attribution.</li><li>Read-only access to import click and impression data at the aggregate level from Google Ads into your Branch account.</li><li>Viewing Google Ads metrics in your Branch Dashboard (your manager (MCC) and children accounts).</li><li>Deep link into in-app experiences (campaign specific)</li></ul><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>In order to enable Google Ads, you first need to:</p><ol><li>Create an account in the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Enable Ads for your Branch account. Please contact our <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">Sales team</a> to learn more about pricing and availability.</li><li>Implement the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>). Once you do this, you can start to <a href="./track-branch-events.html">track events</a>.</li><li>Have admin access to your Google Ads account.</li></ol><h2 id="enable-app-campaigns" tabindex="-1">Enable app campaigns <a class="header-anchor" href="#enable-app-campaigns" aria-label="Permalink to &quot;Enable app campaigns&quot;">​</a></h2><h3 id="_1-link-branch-in-google-ads" tabindex="-1">1. Link Branch in Google Ads <a class="header-anchor" href="#_1-link-branch-in-google-ads" aria-label="Permalink to &quot;1. Link Branch in Google Ads&quot;">​</a></h3><p>After signing into your Google Ads account, click on <strong>Tools</strong> in the sidebar, then click on the <strong>Data manager</strong> tab.</p><p>Then, scroll down to <strong>Popular products</strong>, and select <strong>Third-party app analytics</strong>.</p><p>Click on <strong>Create link ID</strong>.</p><p>Choose <strong>Branch</strong> in the <strong>App analytics provider</strong> dropdown to link Branch to Google Ads.</p><p>You are allowed to link multiple accounts as long as the user connecting has access to all of the accounts you wish to connect. For each app you want to track with Branch, you&#39;ll need to create a different link ID.</p><p>If you manage campaigns for the same app in multiple Google Ads account, you must do one of the following three options:</p><ul><li><p>Use <a href="https://support.google.com/google-ads/answer/3030657" target="_blank" rel="noreferrer">cross-account conversion tracking</a> and set up a link ID with your third-party app analytics provider in your manager account. Once you link at the MCC level, there is one additional step to &quot;share down&quot; the ability for the sub-accounts to utilize these Conversion Events:</p><ul><li>Navigate to <strong>MCC</strong> → <strong>Settings</strong> → <strong>Sub-account Settings</strong> → <strong>Google Ads Conversion account</strong>. For those accounts you wish to share conversions from the MCC, the “Google Ads Conversion account” column should be edited to &quot;This Manager.&quot;</li></ul></li><li><p>Or, share a single link ID with another Google Ads account.</p></li><li><p>Or, the account you share from will be the “owner” of the link ID. Only the “owner” of the link ID can share their link ID with other accounts. Any account that has accepted the owner&#39;s invite will be able to import conversions from the corresponding third-party app analytics provider for the app associated with the shared link ID.</p></li></ul><p>Once you create the link IDs, copy them, as you&#39;ll need them for the next step.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Branch validates the link ID generated from Google in order to avoid any human error.</p></div><h3 id="_2-connect-google-ads-in-branch" tabindex="-1">2. Connect Google Ads in Branch <a class="header-anchor" href="#_2-connect-google-ads-in-branch" aria-label="Permalink to &quot;2. Connect Google Ads in Branch&quot;">​</a></h3><p>In the Branch Dashboard on the<a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Ad Partners page</strong></a>under the <strong>Configure</strong> section, find/search for Google AdWords.</p><p>Click the <strong>Sign in with Google</strong> button to authenticate with your Google Ads account.</p><p>After selecting the Adwords accounts to connect with Branch, paste the link IDs from <a href="./enable-google-app-campaigns.html#1-link-branch-in-google-ads">Step 1</a>.</p><p>After inputting your link IDs, Google Ads will be connected to Branch.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>You must add all the accounts that you want to receive SKAN data for. If you only add one, you will only receive SKAN data for that account.</p></div><h3 id="_3-configure-events" tabindex="-1">3. Configure events <a class="header-anchor" href="#_3-configure-events" aria-label="Permalink to &quot;3. Configure events&quot;">​</a></h3><p>After authenticating your Google Ads account to Branch, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_google_adwords?tab=events" target="_blank" rel="noreferrer"><strong>Events Config</strong></a> tab to configure your events.</p><p>It&#39;s important to add your event mappings here for Branch to properly send event metadata to Google Ads for attribution. You should see the events you are tracking with the Branch SDK here when you <strong>Add Event Mappings</strong>. For more details on Google Ads and Branch event &amp; metadata mapping, see the specifications <a href="./google-ads-data-reporting.html">here</a>.</p><h3 id="_4-configure-attribution-windows" tabindex="-1">4. Configure attribution windows <a class="header-anchor" href="#_4-configure-attribution-windows" aria-label="Permalink to &quot;4. Configure attribution windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_google_adwords?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows</strong></a> tab to set windows by attribution type.</p><p>You have full freedom to choose your attribution windows; however, it may cause discrepancies between the Branch and Google Dashboards when comparing.</p><p>Google&#39;s Recommended Attribution Windows:</p><table tabindex="0"><thead><tr><th>Attribution type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>60 days</td></tr><tr><td>click to install</td><td>30 days</td></tr><tr><td>click to conversion event</td><td>90 days</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event</td><td>1 day</td></tr></tbody></table><h3 id="_5-import-events-to-google" tabindex="-1">5. Import events to Google <a class="header-anchor" href="#_5-import-events-to-google" aria-label="Permalink to &quot;5. Import events to Google&quot;">​</a></h3><p>After setting up events and the attribution windows in Branch, you will need to <a href="https://support.google.com/google-ads/answer/7382633" target="_blank" rel="noreferrer">import app conversion data to Google Ads</a>.</p><h4 id="newly-generated-conversions" tabindex="-1">Newly generated conversions <a class="header-anchor" href="#newly-generated-conversions" aria-label="Permalink to &quot;Newly generated conversions&quot;">​</a></h4><p>When you create new conversion events in Branch, Google Ads requires specific activation steps before it can recognize and track them.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>For Google Ads to recognize your newly generated conversions, it is essential to <strong>activate your app and execute the designated in-app actions at least once</strong>.</p><p>Please note that it might take <strong>up to 6 hours</strong> for the event conversions to be queued and processed. Once added to the queue, you can import these conversions, and their status will shift from &quot;No recent conversion&quot; to &quot;Recording conversion.&quot;</p></div><h4 id="first-open-event-conversions" tabindex="-1">First open event conversions <a class="header-anchor" href="#first-open-event-conversions" aria-label="Permalink to &quot;First open event conversions&quot;">​</a></h4><p>For any <code>first_open</code> event conversions, please <strong>ensure that you enable the &quot;account default&quot; setting</strong> for a conversion goal so that primary conversion actions within that goal can be tracked as conversions in your reporting.</p><p>For more information, please refer to Google&#39;s <a href="https://support.google.com/google-ads/answer/4677036?hl=en&amp;co=ADWORDS.IsAWNCustomer%3Dtrue&amp;oco=0" target="_blank" rel="noreferrer">documentation</a>.</p><h3 id="_6-launch-google-ads-app-campaigns" tabindex="-1">6. Launch Google Ads app campaigns <a class="header-anchor" href="#_6-launch-google-ads-app-campaigns" aria-label="Permalink to &quot;6. Launch Google Ads app campaigns&quot;">​</a></h3><p>In Google Ads, after you&#39;ve created and optimized your App Install/Engagement campaign, you can create your ad group(s), which dynamically creates formats for various formats. Here is where you can set additional campaign configurations.</p><p>You must create separate campaigns for iOS and Android:</p><p>Once you finish, review the information and launch your campaign.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If your campaigns are agency-managed, please see additional steps <a href="./what-is-a-self-attributing-network.html">here</a>.</p></div><h2 id="deep-linking-from-google-app-campaigns" tabindex="-1">Deep linking from Google App campaigns <a class="header-anchor" href="#deep-linking-from-google-app-campaigns" aria-label="Permalink to &quot;Deep linking from Google App campaigns&quot;">​</a></h2><p>Please consult with your app development team to set up deep linking for your Google App Campaigns.</p><h4 id="app-install-campaign-deep-linking" tabindex="-1">App install campaign deep linking <a class="header-anchor" href="#app-install-campaign-deep-linking" aria-label="Permalink to &quot;App install campaign deep linking&quot;">​</a></h4><p>The only type of deep linking supported by UAC is Branch&#39;s SAN deferred deep linking feature. Please follow our guide <a href="./san-deferred-deep-linking.html"><strong>here</strong></a> on how to set it up.</p><h4 id="app-engagement-campaign-deep-linking" tabindex="-1">App engagement campaign deep linking <a class="header-anchor" href="#app-engagement-campaign-deep-linking" aria-label="Permalink to &quot;App engagement campaign deep linking&quot;">​</a></h4><p>Engagement campaigns have the ability to deep link using the following:</p><ul><li><a href="./ios-universal-links.html">iOS Universal Links</a></li><li><a href="./android-app-links.html">Android App Links</a></li><li><a href="./in-app-routing.html">URI schemes</a></li></ul><h2 id="google-ads-conversion-reporting" tabindex="-1">Google ads conversion reporting <a class="header-anchor" href="#google-ads-conversion-reporting" aria-label="Permalink to &quot;Google ads conversion reporting&quot;">​</a></h2><p>Branch enables Google Ads conversion tracking for users who opted out of ATT on iOS 14.5+ devices. Branch transmits the Google Ads <code>gbraid</code>, a campaign identifier for app re-engagement via deep links. The Branch SDK then retains the <code>gbraid</code> to link it with events over a 30-day period.</p><h3 id="enable-google-ads-conversion-reporting" tabindex="-1">Enable Google Ads conversion reporting <a class="header-anchor" href="#enable-google-ads-conversion-reporting" aria-label="Permalink to &quot;Enable Google Ads conversion reporting&quot;">​</a></h3><h4 id="_1-update-your-ios-app" tabindex="-1">1. Update your iOS app <a class="header-anchor" href="#_1-update-your-ios-app" aria-label="Permalink to &quot;1. Update your iOS app&quot;">​</a></h4><p>Be sure to update your iOS app with the latest version of the <a href="./ios-version-history.html">Branch iOS SDK</a> to support <code>gbraid</code> handling to share the aggregated identifier with Google on post-install or open events when a user is opted out of ATT on the iOS 14.5+ devices.</p><h4 id="_2-track-events" tabindex="-1">2. Track events <a class="header-anchor" href="#_2-track-events" aria-label="Permalink to &quot;2. Track events&quot;">​</a></h4><p><a href="./track-branch-events.html">Track events</a> with the Branch SDK in order to attribute post-install events in Google&#39;s reporting.</p><p>To learn more about Google Ads campaign identifiers, click <a href="./google-ads.html#campaign-identifiers">here</a>.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="how-do-i-handle-multiple-google-ad-accounts" tabindex="-1">How do I handle multiple Google Ad accounts? <a class="header-anchor" href="#how-do-i-handle-multiple-google-ad-accounts" aria-label="Permalink to &quot;How do I handle multiple Google Ad accounts?&quot;">​</a></h4><p>First, it is not necessary to connect all Google Ads accounts. However, you must connect the Google Ads account that owns in-app conversions for your mobile app. Often, this is the MCC account.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>Inside an MCC, it is possible to configure which account (the MCC or the child account) is responsible for conversions. Ensure that you create link IDs with the account that is noted as the Conversion Account under the <strong>MCC &gt; Management</strong> tab.</p><p><strong>Note:</strong> Do not authenticate a single ad account to multiple Branch apps (ex. Live and Test apps) as that will cause issues with authentication and Dashboard reports.</p></div><p>If you only have access to the child account (but that account is attached to an MCC), you can see which account is recording conversions within the child account as well, by going to <strong>Tools &gt; Conversions &gt; Settings &gt; Conversion Account</strong> in Google Ads.</p>',64)])])}const u=o(r,[["render",i]]);export{g as __pageData,u as default};
